// Parse mmr MCP responses
function mcpText(item) {
  try {
    const r = item.json;
    // Streamable HTTP may return result.content[0].text
    const content = (r.result || {}).content || [];
    if (content.length) return JSON.parse(content[0].text || '{}');
    // Or result directly
    return r.result || {};
  } catch { return {}; }
}

const fire = mcpText($('Get Fire Restrictions (mmr MCP)').first());
const eas  = mcpText($('Get EAS Alerts (mmr MCP)').first());

const sd = $getWorkflowStaticData('global');

const alerts = [];

// Fire restriction change
const fireLevel = String(fire.level || fire.restriction_level || '').toLowerCase();
if (fireLevel && fireLevel !== (sd.lastFireLevel || '')) {
  sd.lastFireLevel = fireLevel;
  const closed = ['high','very high','extreme','closure'].some(w => fireLevel.includes(w));
  alerts.push({
    topic: 'alerts',
    title: `🔥 Fire Restriction Update — Sedona`,
    body:  `${fire.summary || fire.description || ('Level: ' + fireLevel)}. Stay safe out there.`,
    url:   '/weather.html',
    tag:   'kazm-fire'
  });
}

// New EAS alert
const easAlerts = eas.alerts || eas.features || [];
const easIds = easAlerts.map(a => a.id || a.properties?.id || '').filter(Boolean);
const newIds = easIds.filter(id => !(sd.lastEasIds || []).includes(id));
if (newIds.length) {
  sd.lastEasIds = easIds.slice(0, 50);
  const top = easAlerts.find(a => newIds.includes(a.id || (a.properties || {}).id));
  const props = top?.properties || top || {};
  alerts.push({
    topic: 'alerts',
    title: `⚠️ ${props.event || 'Emergency Alert'} — Sedona Area`,
    body:  `${props.headline || props.description || 'Check mellowmountainradio.com for details.'} `.slice(0, 180),
    url:   '/weather.html',
    tag:   'kazm-eas'
  });
}

return alerts.map(a => ({ json: a }));
